"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["1882"],{9723(e,n,i){i.r(n),i.d(n,{metadata:()=>a,default:()=>p,frontMatter:()=>t,contentTitle:()=>r,toc:()=>l,assets:()=>c});var a=JSON.parse('{"id":"Planets & Points/Pluto","title":"Pluto","description":"PLUTO","source":"@site/docs/Planets & Points/Pluto.md","sourceDirName":"Planets & Points","slug":"/Planets & Points/Pluto","permalink":"/Planets & Points/Pluto","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Planets & Points/Pluto.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Neptune","permalink":"/Planets & Points/Neptune"},"next":{"title":"Saturn","permalink":"/Planets & Points/Saturn"}}'),o=i(4848),s=i(8453);let t={},r,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.p,{children:"PLUTO"}),"\n",(0,o.jsx)(n.p,{children:"Principle:"}),"\n",(0,o.jsx)(n.p,{children:"Force majeure or providence, invisible forces or powers."}),"\n",(0,o.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"The will or wish to exercise power, the manifestation of unconscious powers, ruthless frankness or candidness, the urge to influence the masses, propagandist aspirations and objectives, understanding of the masses."}),"\n"]}),"\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Ruthless use of force or coercion, inclination to incite, a fanatical zeal to state one's own doctrinal principles, to agitate, convulsions and spasms."}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"The collective consciousness. \u2013 Regeneration."}),"\n",(0,o.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"Persons who can be said to exercise a magical influence over the masses, such as propagandists, actors, public speakers and politicians."}),"\n",(0,o.jsx)(n.p,{children:"Position in Houses and Signs:"}),"\n",(0,o.jsx)(n.p,{children:"I. Subconscious forces try to come to light in order to assist in the recognition of new and entirely novel ideas. Extraordinary energy, the power to assert oneself, the qualities of leadership. The craving for power."}),"\n",(0,o.jsx)(n.p,{children:"II. The urge to acquire, the striving for obtaining possessions, great dependence on money and property, the influence of great gain or loss upon destiny."}),"\n",(0,o.jsx)(n.p,{children:"III. Intellectual power of assertion as scientist, orator, mass-suggestion, organiser, adventurer. \u2013 Ruthless behaviour with regard to society or the social order and with regard to generally accepted views."}),"\n",(0,o.jsx)(n.p,{children:"IV. Hereditary qualities mould destiny, the acceptance of unusual tasks, a contemplative nature, the magician, solitary search and research in new fields."}),"\n",(0,o.jsx)(n.p,{children:"V. Strongly dynamic urges or forces in the emotional spheres, the tendency to speculate, the desire to exercise one's power, rule by force. \u2013 Extraordinary achievements in a special field."}),"\n",(0,o.jsx)(n.p,{children:"VI. An inquisitive mind, the desire to collect, achieving much with the simplest means, the pursuit of scientific objectives with fanatical zeal."}),"\n",(0,o.jsx)(n.p,{children:"VII. An extraordinary power of assertion with regard to the environment, the family and the public. The manifestation of genius, strange celebrities who benefit or harm humanity."}),"\n",(0,o.jsx)(n.p,{children:"VIII. Subconscious forces associate themselves with a suggestive influence upon other people. Fanaticism. One's share in tragic events. Record-achievements through tenacity and endurance."}),"\n",(0,o.jsx)(n.p,{children:"IX. An extremely strong urge to gain higher knowledge, the striving for the unattainable, pioneer-work in the spiritual-mental or religious sphere, the love of travel, the urge to experience life."}),"\n",(0,o.jsx)(n.p,{children:"X. An untiring struggle for recognition, power and independence. The dictator. The successful realisation of new ideas, plans and inventions. The acceptance of dangerous positions."}),"\n",(0,o.jsx)(n.p,{children:"XI. A strong communal sense, wealth of plans, the urge to reform, advancement in life with the help of other people, popularity. \u2013 Exaggerated plans and hopes."}),"\n",(0,o.jsx)(n.p,{children:"XII. The desire to live in seclusion and retirement, work in secrecy and in metaphysical realms. Universalism. The ability to withstand temptation must be proven."}),"\n",(0,o.jsx)(n.p,{children:"N.B."}),"\n",(0,o.jsx)(n.p,{children:"The influence of Pluto has not yet been investigated to the full so that no definitive statements can be made. For this reason, we would welcome any suggestions and new data from the reader."}),"\n",(0,o.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,o.jsx)(n.p,{children:"PLUTON"}),"\n",(0,o.jsx)(n.p,{children:"Zasada:"}),"\n",(0,o.jsx)(n.p,{children:"Si\u0142a wy\u017Csza lub opatrzno\u015B\u0107, niewidzialne si\u0142y lub moce."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsx)(n.li,{children:"Wola lub ch\u0119\u0107 wywierania w\u0142adzy, manifestacja nie\u015Bwiadomych mocy, bezwzgl\u0119dna szczero\u015B\u0107 lub otwarto\u015B\u0107, pragnienie wp\u0142ywania na masy, aspiracje i cele propagandowe, zrozumienie mas."}),"\n",(0,o.jsx)(n.li,{children:"Bezwzgl\u0119dne u\u017Cycie si\u0142y lub przymusu, sk\u0142onno\u015B\u0107 do pod\u017Cegania, fanatyczna gorliwo\u015B\u0107 w formu\u0142owaniu w\u0142asnych zasad doktrynalnych, do agitowania, konwulsje i skurcze."}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Zbiorowa \u015Bwiadomo\u015B\u0107. \u2013 Regeneracja."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Osoby, o kt\xf3rych mo\u017Cna powiedzie\u0107, \u017Ce wywieraj\u0105 magiczny wp\u0142yw na masy, takie jak propagandy\u015Bci, aktorzy, m\xf3wcy publiczni i politycy."}),"\n",(0,o.jsx)(n.p,{children:"Pozycja w domach i znakach:"}),"\n",(0,o.jsx)(n.p,{children:"I. Si\u0142y pod\u015Bwiadomo\u015Bci pr\xf3buj\u0105 wyj\u015B\u0107 na \u015Bwiat\u0142o dzienne, aby pom\xf3c w uznaniu nowych i ca\u0142kowicie nowatorskich idei. Niezwyk\u0142a energia, si\u0142a do asertywnego wyra\u017Cania siebie (przeforsowania siebie), cechy przyw\xf3dcze. \u0141aknienie w\u0142adzy."}),"\n",(0,o.jsx)(n.p,{children:"II. Pragnienie zdobywania, d\u0105\u017Cenie do uzyskania posiad\u0142o\u015Bci, wielka zale\u017Cno\u015B\u0107 od pieni\u0119dzy i w\u0142asno\u015Bci, wp\u0142yw wielkiego zysku lub straty na przeznaczenie."}),"\n",(0,o.jsx)(n.p,{children:"III. Intelektualna si\u0142a przebicia jako naukowiec, m\xf3wca, sugestia masowa, organizator, poszukiwacz przyg\xf3d. \u2013 Bezwzgl\u0119dne zachowanie w stosunku do spo\u0142ecze\u0144stwa lub porz\u0105dku spo\u0142ecznego oraz w stosunku do og\xf3lnie przyj\u0119tych pogl\u0105d\xf3w."}),"\n",(0,o.jsx)(n.p,{children:"IV. Cechy dziedziczne kszta\u0142tuj\u0105 przeznaczenie, akceptacja niezwyk\u0142ych zada\u0144, kontemplacyjna natura, mag, samotne poszukiwania i badania na nowych polach."}),"\n",(0,o.jsx)(n.p,{children:"V. Silnie dynamiczne impulsy lub si\u0142y w sferach emocjonalnych, tendencja do spekulacji, pragnienie wywierania swojej w\u0142adzy, rz\u0105dy si\u0142\u0105. \u2013 Niezwyk\u0142e osi\u0105gni\u0119cia w specjalnej dziedzinie."}),"\n",(0,o.jsx)(n.p,{children:"VI. Dociekliwy umys\u0142, pragnienie kolekcjonowania, osi\u0105ganie wiele najprostszymi \u015Brodkami, d\u0105\u017Cenie do cel\xf3w naukowych z fanatyczn\u0105 gorliwo\u015Bci\u0105."}),"\n",(0,o.jsx)(n.p,{children:"VII. Niezwyk\u0142a si\u0142a przebicia w stosunku do otoczenia, rodziny i og\xf3\u0142u (publiczno\u015Bci). Manifestacja geniuszu, osobliwe osobisto\u015Bci (celebryci), kt\xf3re przynosz\u0105 po\u017Cytek lub szkod\u0119 ludzko\u015Bci."}),"\n",(0,o.jsx)(n.p,{children:"VIII. Si\u0142y pod\u015Bwiadomo\u015Bci \u0142\u0105cz\u0105 si\u0119 z sugestywnym wp\u0142ywem na innych ludzi. Fanatyzm. Udzia\u0142 w tragicznych wydarzeniach. Rekordowe osi\u0105gni\u0119cia dzi\u0119ki nieust\u0119pliwo\u015Bci i wytrwa\u0142o\u015Bci."}),"\n",(0,o.jsx)(n.p,{children:"IX. Niezwykle silne pragnienie zdobycia wy\u017Cszej wiedzy, d\u0105\u017Cenie do nieosi\u0105galnego, praca pionierska w sferze duchowo-umys\u0142owej lub religijnej, mi\u0142o\u015B\u0107 do podr\xf3\u017Cy, pragnienie do\u015Bwiadczania \u017Cycia."}),"\n",(0,o.jsx)(n.p,{children:"X. Niestrudzona walka o uznanie, w\u0142adz\u0119 i niezale\u017Cno\u015B\u0107. Dyktator. Udana realizacja nowych pomys\u0142\xf3w, plan\xf3w i wynalazk\xf3w. Akceptacja niebezpiecznych stanowisk."}),"\n",(0,o.jsx)(n.p,{children:"XI. Silne poczucie wsp\xf3lnoty, bogactwo plan\xf3w, pragnienie reformowania, awans w \u017Cyciu z pomoc\u0105 innych ludzi, popularno\u015B\u0107. \u2013 Przesadne plany i nadzieje."}),"\n",(0,o.jsx)(n.p,{children:"XII. Pragnienie \u017Cycia w odosobnieniu i na odosobnieniu, praca w tajemnicy i w obszarach metafizycznych. Uniwersalizm. Zdolno\u015B\u0107 do opierania si\u0119 pokusom musi zosta\u0107 udowodniona."}),"\n",(0,o.jsx)(n.p,{children:"N.B. (Uwaga)"}),"\n",(0,o.jsx)(n.p,{children:"Wp\u0142yw Plutona nie zosta\u0142 jeszcze w pe\u0142ni zbadany, tak wi\u0119c nie mo\u017Cna sformu\u0142owa\u0107 \u017Cadnych ostatecznych twierdze\u0144. Z tego powodu ch\u0119tnie przyjmiemy wszelkie sugestie i nowe dane od czytelnika."})]})}function p(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>t,x:()=>r});var a=i(6540);let o={},s=a.createContext(o);function t(e){let n=a.useContext(s);return a.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:t(e.components),a.createElement(s.Provider,{value:n},e.children)}}}]);